def cutOffTree(forest):
    trees = sorted([(forest[r][c], r, c) for r in range(len(forest)) for c in range(len(forest[0])) if forest[r][c] > 1])
    def bfs(sr, sc, tr, tc):
        q = collections.deque([(sr, sc, 0)]); v = {(sr, sc)}
        while q:
            r, c, d = q.popleft()
            if r == tr and c == tc: return d
            for nr, nc in [(r-1,c),(r+1,c),(r,c-1),(r,c+1)]:
                if 0<=nr<len(forest) and 0<=nc<len(forest[0]) and forest[nr][nc] > 0 and (nr,nc) not in v:
                    v.add((nr,nc)); q.append((nr,nc,d+1))
        return -1
    res = 0; sr = sc = 0
    for h, tr, tc in trees:
        d = bfs(sr, sc, tr, tc)
        if d == -1: return -1
        res += d; sr, sc = tr, tc
    return res

